// 3-stufige Zahlungserinnerungen: Tag 7, 14, 21 nach Faelligkeit
const zahlungen = $('Offene Zahlungen laden').all();
const logItems = $('Bereits gesendete Erinnerungen laden').all();

// Set von bereits gesendeten Erinnerungen: telefon_rechnungsNr_stufe
const gesendet = new Set();
for (const item of logItems) {
  const key = `${item.json.Telefon}_${item.json.Rechnungs_Nr}_${item.json.Stufe}`;
  gesendet.add(key);
}

const now = new Date();
const results = [];

for (const item of zahlungen) {
  const data = item.json;

  const status = (data.Status || data.status || '').toLowerCase();
  // Nur offene/ueberfaellige Zahlungen
  if (status === 'bezahlt' || status === 'storniert') continue;

  const name = data.Schueler || data.Name || data.name || '';
  let telefon = data.Telefon || data.telefon || data.Handy || '';
  const betrag = data.Betrag || data.betrag || '0';
  const rechnungsNr = data.Rechnungs_Nr || data.rechnungs_nr || data.Rechnung || '';
  const faelligDatum = data.Faellig || data.faellig || data.Faellig_am || '';
  const beschreibung = data.Beschreibung || data.beschreibung || data.Leistung || 'Fahrschulleistung';

  if (!telefon || !name || !faelligDatum) continue;

  // Telefonnummer bereinigen
  telefon = telefon.toString().replace(/[\s\-\/\(\)]/g, '');
  if (!telefon.startsWith('+')) {
    telefon = '+49' + telefon.replace(/^0/, '');
  }

  // Faelligkeitsdatum parsen
  let faellig;
  try {
    if (faelligDatum.includes('.')) {
      const parts = faelligDatum.split('.');
      faellig = new Date(`${parts[2]}-${parts[1].padStart(2,'0')}-${parts[0].padStart(2,'0')}T00:00:00`);
    } else {
      faellig = new Date(faelligDatum + 'T00:00:00');
    }
  } catch(e) { continue; }

  if (isNaN(faellig.getTime())) continue;

  const tageUeberfaellig = Math.floor((now.getTime() - faellig.getTime()) / (1000 * 60 * 60 * 24));

  // Stufe 1: Tag 7 (freundliche Erinnerung)
  if (tageUeberfaellig >= 7 && tageUeberfaellig < 14) {
    const key = `${telefon}_${rechnungsNr}_stufe1`;
    if (!gesendet.has(key)) {
      results.push({
        json: {
          schuelerName: name,
          schuelerTelefon: telefon,
          betrag,
          rechnungsNr,
          faelligDatum,
          beschreibung,
          tageUeberfaellig,
          stufe: 'stufe1',
          stufeText: 'Freundliche Erinnerung'
        }
      });
    }
  }

  // Stufe 2: Tag 14 (dringende Mahnung)
  if (tageUeberfaellig >= 14 && tageUeberfaellig < 21) {
    const key = `${telefon}_${rechnungsNr}_stufe2`;
    if (!gesendet.has(key)) {
      results.push({
        json: {
          schuelerName: name,
          schuelerTelefon: telefon,
          betrag,
          rechnungsNr,
          faelligDatum,
          beschreibung,
          tageUeberfaellig,
          stufe: 'stufe2',
          stufeText: 'Dringende Mahnung'
        }
      });
    }
  }

  // Stufe 3: Tag 21 (letzte Warnung + Inhaber-Eskalation)
  if (tageUeberfaellig >= 21) {
    const key = `${telefon}_${rechnungsNr}_stufe3`;
    if (!gesendet.has(key)) {
      results.push({
        json: {
          schuelerName: name,
          schuelerTelefon: telefon,
          betrag,
          rechnungsNr,
          faelligDatum,
          beschreibung,
          tageUeberfaellig,
          stufe: 'stufe3',
          stufeText: 'Letzte Warnung'
        }
      });
    }
  }
}

return results.length > 0 ? results : [{ json: { skip: true } }];

